% MATLAB equivalent (must be in calculate_link_budget.m)
function [rx_power_dbm, rx_power_mw] = calculate_link_budget(tx_power_dbm, path_loss_db, rx_gain_db)
    if nargin < 3
        rx_gain_db = 0;
    end
    rx_power_dbm = tx_power_dbm - path_loss_db + rx_gain_db;
    rx_power_mw = 10 ^ (rx_power_dbm / 10);
end

