exercises.solution:
def dbm_to_mw(dbm_value):
    """Converts power from dBm to milliwatts."""
    try:
        # In Python, exponentiation is **, not ^
        mw_value = 10 ** (dbm_value / 10)
        return mw_value
    except TypeError:
        print(f"Error: Invalid input type '{type(dbm_value).__name__}'. Expected a number.")
        return None

# Test cases
test_values = [20, 0, "high"]

for val in test_values:
    result = dbm_to_mw(val)
    if result is not None:
        print(f"{val} dBm = {result:.2f} mW")
